function ModelNotice:OnNoticeResp(pb)
    self._noticeList = pb.list
end


function ModelNotice:OnFollowWeChatListResp(pb,ret)
    local noticeWeChatList = self._noticeWeChatList
    if not noticeWeChatList then
        noticeWeChatList = {}
        self._noticeWeChatList = noticeWeChatList
    end
    local list = pb.list
    for i,v in ipairs(list) do
        noticeWeChatList[v] = v
    end
end

function ModelNotice:IsNoticeWeChat(weChat)
    local noticeWeChatList = self._noticeWeChatList
    if not noticeWeChatList then return false end
    if noticeWeChatList[weChat] then
        return false
    else
        return true
    end
end

function ModelNotice:HasNotice()
    if self._noticeList then
        local cnt = #self._noticeList
        return cnt>0
    end
    return false
end

function ModelNotice:CheckPopPlatformNotice()
    local recordTime = LPlayerPrefs.platformNotice

    local lastTime =tonumber(recordTime)
    if not lastTime then
        return true
    end
    local curTime = os.time()
    local timeDif = curTime-lastTime
    if timeDif> 86400 then
        return true
    end
    local date = LUtil.OSDate("*t",lastTime)
    local oldDay = date.day
    date = LUtil.OSDate("*t",curTime)
    local newDay = date.day
    if newDay>oldDay then
        return true
    end

    return false
end

function ModelNotice:CheckPopPlatformGameNotice()
    local recordTime = LPlayerPrefs.platformGameNotice

    local lastTime =tonumber(recordTime)
    if not lastTime then
        return true
    end
    local curTime = GetTimestamp()
    local timeDif = curTime-lastTime
    if timeDif> 86400 then
        return true
    end
    local date = LUtil.OSDate("*t",lastTime)
    local oldDay = date.day
    date = LUtil.OSDate("*t",curTime)
    local newDay = date.day
    if newDay>oldDay then
        return true
    end

    return false
end

function ModelNotice:SetNeedWaitGameNotice(needWait)
    self._bulletinWait = needWait
end

function ModelNotice:CheckNeedWaitGameNotice()
    return self._bulletinWait
end

